import strawberry
from strawberry import Schema, Query
from sqlalchemy import create_engine
from sqlalchemy.orm import sessionmaker

# Define the database connection and sessionmaker
engine = create_engine("sqlite:///products.db")
Session = sessionmaker(bind=engine)

# Define the GraphQL schema
@strawberry.type
class Product:
    id: int
    name: str
    description: str
    price: float
    reviews: List[Review]
    sellers: List[Seller]
    categories: List[Category]
    images: List[Image]

@strawberry.type
class Review:
    id: int
    product_id: int
    rating: int
    comment: str

@strawberry.type
class Seller:
    id: int
    name: str
    email: str

@strawberry.type
class Category:
    id: int
    name: str

@strawberry.type
class Image:
    id: int
    product_id: int
    url: str

# Define the GraphQL query
@Query
def get_products():
    session = Session()
    products = session.query(Product).all()
    return products

# Define the GraphQL mutation for creating a new product
@Mutation
def create_product(name: str, description: str, price: float):
    session = Session()
    product = Product(name=name, description=description, price=price)
    session.add(product)
    session.commit()
    return product

# Define the GraphQL mutation for updating a product
@Mutation
def update_product(id: int, name: str, description: str, price: float):
    session = Session()
    product = session.query(Product).get(id)
    if product is None:
        return None
    product.name = name
    product.description = description
    product.price = price
    session.commit()
    return product

# Define the GraphQL mutation for deleting a product
@Mutation
def delete_product(id: int):
    session = Session()
    product = session.query(Product).get(id)
    if product is None:
        return None
    session.delete(product)
    session.commit()
    return True

# Define the GraphQL subscription for new products
@Subscription
def new_products():
    session = Session()
    products = session.query(Product).all()
    return products